import math

def add(a, b):
    return a + b

def multiply(a, b):
    return a * b

def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero")
    return a / b

def power(a, b):
    return math.pow(a, b)

print(add(2, 3))
print(multiply(4, 5))
print(divide(10, 2))
print(power(2, 8))
